// Helper functions for easy access
export const getAsset = (type, key) => {
  switch (type) {
    case 'image': return IMAGES_MAP[key];
    case 'audio': return AUDIOS_MAP[key];
    case 'video': return VIDEOS_MAP[key];
    default: return null;
  }
};
